  return <div className="grid min-h-[300px] grid-cols-3 grid-rows-[repeat(3,min-content)] gap-2">
      <Button variant="outline" onClick={() => {
      toast("Title", {
        description: "Description",
        action: {
          label: "Action",
          onClick: () => alert("clicked")
        },
        cancel: {
          label: <Icon name="RiCloseFill" size={20} />,
          onClick: () => null
        }
      });
    }}>
        Toast
      </Button>
      <Button variant="outline" onClick={() => {
      toast.warning("Title", {
        description: "Description",
        action: {
          label: "Action",
          onClick: () => alert("clicked")
        },
        cancel: {
          label: <Icon name="RiCloseFill" size={20} />,
          onClick: () => null
        }
      });
    }}>
        Toast (Warning)
      </Button>
      <Button variant="outline" onClick={() => {
      toast.success("Title", {
        description: "Description",
        action: {
          label: "Action",
          onClick: () => alert("clicked")
        },
        cancel: {
          label: <Icon name="RiCloseFill" size={20} />,
          onClick: () => null
        }
      });
    }}>
        Toast (Success)
      </Button>
      <Button variant="outline" onClick={() => {
      toast.error("Title", {
        description: "Description",
        action: {
          label: "Action",
          onClick: () => alert("clicked")
        },
        cancel: {
          label: <Icon name="RiCloseFill" size={20} />,
          onClick: () => null
        }
      });
    }}>
        Toast (Error)
      </Button>
      <Button variant="outline" onClick={() => {
      toast.info("Title", {
        description: "Description",
        action: {
          label: "Action",
          onClick: () => alert("clicked")
        },
        cancel: {
          label: <Icon name="RiCloseFill" size={20} />,
          onClick: () => null
        }
      });
    }}>
        Toast (Info)
      </Button>
      <Button variant="outline" onClick={() => {
      const promise = () => new Promise(resolve => setTimeout(() => resolve({}), 2000));
      toast.promise(promise, {
        loading: "Loading",
        description: "Description",
        success: () => "Success",
        error: () => "Error",
        action: {
          label: "Action",
          onClick: () => alert("clicked")
        },
        cancel: {
          label: <Icon name="RiCloseFill" size={20} />,
          onClick: () => null
        }
      });
    }}>
        Toast promise (success)
      </Button>
      <Button variant="outline" onClick={() => {
      const promise = () => new Promise((_, reject) => setTimeout(reject, 2000));
      toast.promise(promise, {
        loading: "Loading",
        description: "Description",
        success: () => "Success",
        error: () => "Error",
        action: {
          label: "Action",
          onClick: () => alert("clicked")
        },
        cancel: {
          label: <Icon name="RiCloseFill" size={20} />,
          onClick: () => null
        }
      });
    }}>
        Toast promise (error)
      </Button>
    </div>;
